import React, { useState, useEffect } from "react";
import { Container, Accordion, Row, Col, ProgressBar, Table, Spinner, Alert } from "react-bootstrap";
import "bootstrap/dist/css/bootstrap.min.css";

export default function TimeTable() {
  const [timetableData, setTimetableData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchTimeTable = async () => {
      try {
        const res = await fetch("http://localhost:65000/api/students/gettimetable", {
          credentials: "include",
        });

        if (!res.ok) throw new Error("Failed to fetch timetable");

        const data = await res.json();
        setTimetableData(data);
        setLoading(false);
      } catch (err) {
        setError(err.message);
        setLoading(false);
      }
    };

    fetchTimeTable();
  }, []);

  const getProgressVariant = (count) => {
    if (count >= 2) return "success";
    if (count === 1) return "warning";
    return "danger";
  };

  if (loading)
    return (
      <Container className="text-center my-5">
        <Spinner animation="border" />
        <p>Loading timetable...</p>
      </Container>
    );

  if (error)
    return (
      <Container className="my-5">
        <Alert variant="danger">{error}</Alert>
      </Container>
    );

  // Group timetable by day
  const daysOfWeek = ["monday", "tuesday", "wednesday", "thursday", "friday"];
  const timetableByDay = {};
  daysOfWeek.forEach((day) => {
    timetableByDay[day] = timetableData.timetable.filter(
      (slot) => slot.day === day
    );
  });

  const allKeys = daysOfWeek.map((_, idx) => idx.toString());

  return (
    <Container className="my-4">
      <h2 className="mb-4 text-center" style={{ color: "#2c3e50" }}>
        TimeTable - Semester {timetableData.semester}
      </h2>

      <Accordion defaultActiveKey={allKeys} alwaysOpen>
        {daysOfWeek.map((day, index) => {
          const slots = timetableByDay[day];
          return (
            <Accordion.Item eventKey={index.toString()} key={day}>
              <Accordion.Header>
                <Row className="w-100 align-items-center">
                  <Col xs={6}>
                    <strong>{day.charAt(0).toUpperCase() + day.slice(1)}</strong>
                  </Col>
                  <Col xs={6}>
                    <ProgressBar
                      now={slots.length}
                      max={2}
                      variant={getProgressVariant(slots.length)}
                      label={`${slots.length} Classes`}
                    />
                  </Col>
                </Row>
              </Accordion.Header>
              <Accordion.Body>
                {slots.length === 0 ? (
                  <p>No classes scheduled.</p>
                ) : (
                  <div className="table-responsive">
                    <Table striped bordered hover>
                      <thead className="table-dark">
                        <tr>
                          <th>Time</th>
                          <th>Course</th>
                          <th>Section</th>
                          <th>Room</th>
                          <th>Type</th>
                          <th>Faculty</th>
                        </tr>
                      </thead>
                      <tbody>
                        {slots.map((slot, idx) => (
                          <tr key={idx}>
                            <td>
                              {slot.startTime} - {slot.endTime}
                            </td>
                            <td>
                              <strong>{slot.courseCode}</strong> - {slot.courseName}
                            </td>
                            <td>{slot.section}</td>
                            <td>{slot.room}</td>
                            <td>{slot.classType}</td>
                            <td>{slot.facultyName}</td>
                          </tr>
                        ))}
                      </tbody>
                    </Table>
                  </div>
                )}
              </Accordion.Body>
            </Accordion.Item>
          );
        })}
      </Accordion>
    </Container>
  );
}
